```javascript
function toArrayToObject(array) {
  const resultObject = {};

  array.forEach(element => {
    resultObject[element.age] = element.name;
  });

  return resultObject;
}

const inputArray = [
  { age: "13", name: "Monk" },
  { age: "15", name: "Lokavit" },
  { age: "17", name: "Satya" },
];

const outputObject = toArrayToObject(inputArray);
console.log(outputObject);
```

